        first = goals[0]
        elapsed = first.get('time', {}).get('elapsed') or 0
        extra   = first.get('time', {}).get('extra') or 0
        minute  = elapsed + extra
        home_name = ''   # verrÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ  confrontato con il nome squadra di casa dalla partita
