# ── INGEST ENDPOINT ────────────────────────────────────────────────────────────────────────────
def _build_goals_html_ingest(goals):
    parts = []
    for g in goals:
        team = g.get("team", "home")
        minute = g.get("min", g.get("minute", g.get("elapsed", 0)))
        player = g.get("player", g.get("scorer", "N/D"))
        side = "home" if team in ("home", "casa") else "away"
        parts.append(f'<span class="goal-{side}">{minute}\' {player}</span>')
    return " ".join(parts)

def _build_goals_text_ingest(goals):
    parts = []
    for g in goals:
        team = g.get("team", "home")
        minute = g.get("min", g.get("minute", g.get("elapsed", 0)))
        player = g.get("player", g.get("scorer", "N/D"))
        side = "H" if team in ("home", "casa") else "A"
        parts.append(f"{minute}' {player} ({side})")
    return ", ".join(parts)

def _fg_result_ingest(fg_team, ft_home, ft_away):
    if fg_team == "home":
        if ft_home > ft_away: return "W"
        elif ft_home == ft_away: return "D"
        else: return "L"
    else:
        if ft_away > ft_home: return "W"
        elif ft_away == ft_home: return "D"
        else: return "L"

@app.route("/api/ingest", methods=["POST"])
def api_ingest():
    expected_token = os.environ.get("INGEST_TOKEN", "")
    received_token = request.headers.get("X-Ingest-Token", "")
    if not expected_token:
        return jsonify({"error": "INGEST_TOKEN not set"}), 500
    if not hmac.compare_digest(received_token, expected_token):
        return jsonify({"error": "unauthorized"}), 401

    data = request.get_json(force=True) or {}

    required = ["league_id", "league_name", "season", "date_str",
                "home_team", "away_team", "ft_home", "ft_away",
                "first_goal_min", "first_goal_team"]
    for field in required:
        if data.get(field) is None:
            return jsonify({"error": f"missing field: {field}"}), 400

    fg_min = int(data["first_goal_min"])
    if fg_min > 16:
        return jsonify({"error": "first_goal_min must be <= 16"}), 400

    fixture_id = data.get("fixture_id")
    if fixture_id:
        existing = query("SELECT id FROM matches WHERE fixture_id=?", (int(fixture_id),))
        if existing:
            return jsonify({"ok": True, "inserted": False, "reason": "duplicate"})

    league_id  = int(data["league_id"])
    league_name = str(data["league_name"])
    season     = int(data["season"])
    date_str   = str(data["date_str"])
    time_str   = str(data.get("time_str", ""))
    home_team  = str(data["home_team"])
    away_team  = str(data["away_team"])
    ht_home    = int(data.get("ht_home", 0))
    ht_away    = int(data.get("ht_away", 0))
    ft_home    = int(data["ft_home"])
    ft_away    = int(data["ft_away"])
    st_home    = ft_home - ht_home
    st_away    = ft_away - ht_away
    total_goals = ft_home + ft_away
    ht_goals   = ht_home + ht_away
    st_goals   = st_home + st_away
    btts       = 1 if ft_home > 0 and ft_away > 0 else 0
    result     = "H" if ft_home > ft_away else ("D" if ft_home == ft_away else "A")
    fg_team    = str(data["first_goal_team"])
    fg_result  = _fg_result_ingest(fg_team, ft_home, ft_away)
    goals_list = data.get("goals", [])
    goals_html = _build_goals_html_ingest(goals_list)
    goals_text = _build_goals_text_ingest(goals_list)

    try:
        from datetime import datetime as _dt
        dt = _dt.strptime(f"{date_str} {time_str or '00:00'}", "%Y-%m-%d %H:%M")
        sort_date = dt.strftime("%Y%m%d%H%M")
    except Exception:
        sort_date = date_str.replace("-", "") + "0000"

    existing_league = query("SELECT id FROM leagues WHERE id=?", (league_id,))
    if not existing_league:
        try:
            execute("INSERT OR IGNORE INTO leagues (id, name) VALUES (?,?)", (league_id, league_name))
        except Exception:
            pass

    execute("""
        INSERT INTO matches (
            fixture_id, league_id, season, date_str, sort_date, time_str,
            home_team, away_team, ht_home, ht_away, st_home, st_away,
            ft_home, ft_away, total_goals, ht_goals, st_goals,
            btts, result, goals_html, goals_text,
            first_goal_min, first_goal_team, fg_result, is_archived
        ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,1)
    """, (fixture_id, league_id, season, date_str, sort_date, time_str,
          home_team, away_team, ht_home, ht_away, st_home, st_away,
          ft_home, ft_away, total_goals, ht_goals, st_goals,
          btts, result, goals_html, goals_text,
          fg_min, fg_team, fg_result))

    return jsonify({"ok": True, "inserted": True,
                    "match": f"{home_team} {ft_home}-{ft_away} {away_team}"})

@app.route("/api/admin/delete-fixture", methods=["DELETE"])
def admin_delete_fixture():
    expected_token = os.environ.get("INGEST_TOKEN", "")
    received_token = request.headers.get("X-Ingest-Token", "")
    if not expected_token or not hmac.compare_digest(received_token, expected_token):
        return jsonify({"error": "unauthorized"}), 401
    fixture_id = request.args.get("fixture_id", type=int)
    if fixture_id is None:
        return jsonify({"error": "missing fixture_id"}), 400
    execute("DELETE FROM matches WHERE fixture_id=?", (fixture_id,))
    return jsonify({"ok": True, "deleted_fixture_id": fixture_id})


@app.route('/download/league/<path:league_ref>')
def download_league(league_ref):
    """Genera e scarica un file HTML con tutte le partite early-goal di una lega."""
    from flask import Response
    from datetime import datetime

    # Accetta sia ID numerico che nome lega
    try:
        lid = int(league_ref)
        info = query("SELECT id, name FROM leagues WHERE id=?", (lid,))
    except ValueError:
        info = query("SELECT id, name FROM leagues WHERE name=?", (league_ref,))
        if info:
            lid = info[0]['id']
    if not info:
        return jsonify({'error': 'League not found'}), 404
    league_name = info[0]['name']

    matches = query("""
        SELECT season, date_str, sort_date, time_str,
               home_team, away_team,
               ht_home, ht_away, st_home, st_away, ft_home, ft_away,
               goals_html, first_goal_min
        FROM matches
        WHERE league_id=?
        ORDER BY season DESC, sort_date ASC, time_str ASC
    """, (lid,))

    css = (
        'body{font-family:Arial,sans-serif;margin:24px;background:#f5f7fb;color:#172033}'
        'table{width:100%;border-collapse:collapse;background:#fff}'
        'th,td{border:1px solid #d9e0ee;padding:8px 10px;text-align:left;vertical-align:top;font-size:13px}'
        'th{background:#1f3b73;color:#fff}'
        '.away-goal{color:#d11a2a;font-weight:700}'
        'tr:nth-child(even) td{background:#f8faff}'
    )

    now = datetime.now().strftime('%d/%m/%Y, %H:%M:%S')
    count = len(matches)

    rows = []
    for m in matches:
        parts = (m['date_str'] or '').split('-')
        date_it = f"{parts[2]}/{parts[1]}/{parts[0]}" if len(parts) == 3 else (m['date_str'] or '')
        ht = f"{m['ht_home']}-{m['ht_away']}"
        st = f"{m['st_home']}-{m['st_away']}"
        ft = f"{m['ft_home']}-{m['ft_away']}"
        rows.append(
            f"<tr><td>{m['season']}</td><td>{date_it}</td><td>{m['time_str'] or ''}</td>"
            f"<td>{m['home_team']}</td><td>{m['away_team']}</td><td>{league_name}</td>"
            f"<td>{ht}</td><td>{st}</td><td>{ft}</td>"
            f"<td>{m['goals_html'] or ''}</td><td>-</td><td>-</td><td>-</td></tr>"
        )

    if not rows:
        rows.append("<tr><td colspan='13'>Nessuna partita trovata con primo gol entro il 16'.</td></tr>")

    html = f"""<!DOCTYPE html>
<html lang="it">
<head>
<meta charset="utf-8">
<title>{league_name} - Primo gol entro 16 minuti</title>
<style>{css}</style>
</head>
<body>
<h1>{league_name} - Primo gol entro il 16 minuto</h1>
<p>Generato il {now} | Partite trovate: {count}</p>
<table>
<thead>
<tr><th>Stagione</th><th>Data</th><th>Ora</th><th>Casa</th><th>Ospite</th><th>Campionato</th>
<th>1T</th><th>2T</th><th>Finale</th><th>Minuti gol</th><th>Quota 1</th><th>Quota X</th><th>Quota 2</th></tr>
</thead>
<tbody>
{"".join(rows)}
</tbody>
</table>
</body>
</html>"""

    filename = f'{lid}_gol-16min.html'
    return Response(
        html,
        mimetype='text/html',
        headers={'Content-Disposition': f'attachment; filename="{filename}"'}
    )

